-- Without this, finding a user by email scans the table
CREATE INDEX idx_users_email ON users (email);

-- Now this lookup is a fast index seek
SELECT id, name FROM users WHERE email = 'ava@x.io';

-- No index on created_at: full scan of 10M rows
SELECT * FROM orders WHERE created_at > '2026-01-01';
-- Planning: 0.1 ms  Execution: 4200 ms

CREATE INDEX idx_orders_created ON orders (created_at);
-- Same query now: Execution: 21 ms

-- BAD: function on the column disables idx_users_email
SELECT * FROM users WHERE LOWER(email) = 'ava@x.io';

-- FIX A: index the expression
CREATE INDEX idx_users_email_lower ON users (LOWER(email));

